// Alert when daily cost exceeds a threshold (in cents).
// The amount field is in cents — 5000 = $50.00.
// Adjust the threshold in the final WHERE clause as needed.
FROM metrics-anthropic_metrics.cost-*
| WHERE anthropic.cost.amount IS NOT NULL
| STATS daily_cost_cents = SUM(anthropic.cost.amount)
| EVAL daily_cost_usd = ROUND(daily_cost_cents / 100.0, 2)
| WHERE daily_cost_cents > 5000
